import{_ as e,o,c as r,a as s}from"./chunks/framework.8tiMeCK-.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_networking/ch12_9.md","filePath":"notes/linux_kernel_networking/ch12_9.md","lastUpdated":null}'),n={name:"notes/linux_kernel_networking/ch12_9.md"};function l(i,t,a,d,g,c){return o(),r("div",null,[...t[0]||(t[0]=[s('<h3 id="_12-9-快速参考-quick-reference" tabindex="-1">12.9 快速参考（Quick Reference） <a class="header-anchor" href="#_12-9-快速参考-quick-reference" aria-label="Permalink to &quot;12.9  快速参考（Quick Reference）&quot;">​</a></h3><p>我们在这一章里走了很远——从最基础的 CSMA/CA 握手，到 802.11n 的 A-MPDU 聚合，再到 802.11s 的多跳路由。这些协议在纸面上是抽象的原理图，但在内核代码里，它们是一个个具体的函数调用、结构体成员和标志位。</p><p>当你真正动手去写驱动或者调试 <code>mac80211</code> 时，你需要的不是大段的原理叙述，而是一份能快速告诉你“这个函数是干什么的”、“那个标志位代表什么”的地图。</p><p>这就是本节存在的意义。它不是用来读的，是用来<strong>查</strong>的。</p><p>这里我列出了本章提到过的一些核心方法，以及那个极为复杂的 <code>ieee80211_rx_status</code> 标志位字典。把这一页当词典用——当你在 <code>drivers/net/wireless</code> 的代码丛林里迷路时，回来看看这里。</p><hr><h3 id="核心方法速查" tabindex="-1">核心方法速查 <a class="header-anchor" href="#核心方法速查" aria-label="Permalink to &quot;核心方法速查&quot;">​</a></h3><p>这些函数大多定义在 <code>net/mac80211/</code> 目录下。为了方便查阅，我按功能将它们分类，并补充了原文中未提及但在调用时至关重要的行为细节。</p><h4 id="_1-block-ack-与聚合-a-mpdu-a-msdu" tabindex="-1">1. Block Ack 与聚合（A-MPDU / A-MSDU） <a class="header-anchor" href="#_1-block-ack-与聚合-a-mpdu-a-msdu" aria-label="Permalink to &quot;1. Block Ack 与聚合（A-MPDU / A-MSDU）&quot;">​</a></h4><p>这部分是 802.11n 提升吞吐量的核心。驱动通常不直接操作这些细节，但如果你想调试为什么聚合没开启，这里就是终点。</p><ul><li><p><strong><code>void ieee80211_send_bar(struct ieee80211_vif *vif, u8 *ra, u16 tid, u16 ssn)</code></strong></p><ul><li><strong>作用</strong>：发送一个 <strong>Block Ack Request (BAR)</strong> 控制帧。</li><li><strong>场景</strong>：当你发送了一堆聚合帧，但对端没给你回 Block Ack，或者你想显式触发对方确认时调用。<code>ssn</code> (Starting Sequence Number) 告诉对方：“从这个序号开始给我确认”。</li></ul></li><li><p><strong><code>int ieee80211_start_tx_ba_session(struct ieee80211_sta *pubsta, u16 tid, u16 timeout)</code></strong></p><ul><li><strong>作用</strong>：启动一个发送端的 Block Ack 会话（ aggregation session）。</li><li><strong>机制</strong>：它会调用驱动层的 <code>ampdu_action()</code> 回调，传入参数 <code>IEEE80211_AMPDU_TX_START</code>。</li><li><strong>注意</strong>：这不是同步的。驱动准备就绪后，必须回调 <code>ieee80211_start_tx_ba_cb()</code> 或 <code>_irqsafe</code> 版本，真正的聚合才会开始。</li></ul></li><li><p><strong><code>int ieee80211_stop_tx_ba_session(struct ieee80211_sta *pubsta, u16 tid)</code></strong></p><ul><li><strong>作用</strong>：停止发送端的 Block Ack 会话。</li><li><strong>机制</strong>：调用驱动的 <code>ampdu_action()</code>，传入 <code>IEEE80211_AMPDU_TX_STOP</code>。驱动随后必须回调 <code>ieee80211_stop_tx_ba_cb()</code> 来完成清理。</li></ul></li><li><p><strong><code>static void ieee80211_send_addba_request(...)</code></strong></p><ul><li><strong>作用</strong>：发送 <strong>ADDBA Request</strong> 管理帧（Action Frame）。</li><li><strong>参数</strong>：<code>buf_size</code> 决定了接收端的聚合窗口大小（通常 64），<code>timeout</code> 决定了会话超时时间。</li></ul></li><li><p><strong><code>void ieee80211_process_addba_request(...)</code></strong></p><ul><li><strong>作用</strong>：接收端处理收到的 ADDBA 请求。这是 <code>mac80211</code> 的核心逻辑，通常不由驱动调用，而是内核在收到 Action Frame 后自动触发。</li></ul></li><li><p><strong><code>static void ieee80211_send_addba_resp(...)</code></strong></p><ul><li><strong>作用</strong>：发送 ADDBA Response。也就是告诉对方“行，我可以聚合”或者“不行，窗口太小”。</li></ul></li><li><p><strong><code>void ieee80211_process_delba(...)</code></strong></p><ul><li><strong>作用</strong>：处理 DELBA 帧。对方不跟你玩了，或者对方通知你停止发送聚合帧。</li></ul></li><li><p><strong><code>void ieee80211_send_delba(...)</code></strong></p><ul><li><strong>作用</strong>：主动发送 DELBA 帧，结束一段友谊。</li></ul></li><li><p><strong><code>static ieee80211_rx_result ieee80211_rx_h_amsdu(struct ieee80211_rx_data *rx)</code></strong></p><ul><li><strong>作用</strong>：在 <strong>RX 路径</strong> 上处理 A-MSDU（聚合 MSDU）。</li><li><strong>细节</strong>：这是 RX Handler 链中的一环。如果硬件把解聚合后的包交给内核，这个函数负责把一个大包拆回多个 SKB。</li></ul></li><li><p><strong><code>static void ieee80211_rx_reorder_ampdu(...)</code></strong></p><ul><li><strong>作用</strong>：处理 A-MPDU 的 <strong>重排序缓冲区</strong>。</li><li><strong>痛点</strong>：因为无线乱序到达很正常，这个函数把乱序的 MPDU 插入窗口，把连续可提交的包交给上层，把缺序的包留着等 BAR。</li></ul></li></ul><h4 id="_2-电源管理" tabindex="-1">2. 电源管理 <a class="header-anchor" href="#_2-电源管理" aria-label="Permalink to &quot;2. 电源管理&quot;">​</a></h4><p>省电逻辑无线里全是坑。STA 想睡，AP 得帮着缓存；STA 醒了，得赶紧拿数据。</p><ul><li><p><strong><code>void ieee80211_send_nullfunc(struct ieee80211_local *local, ... int powersave)</code></strong></p><ul><li><strong>作用</strong>：发送 <strong>Null Data</strong> 帧。</li><li><strong>关键</strong>：这是告诉 AP“我要睡了”或者“我醒了”的信令。通过帧头里的 Power Management 位实现。</li></ul></li><li><p><strong><code>void ieee80211_send_pspoll(...)</code></strong></p><ul><li><strong>作用</strong>：发送 <strong>PS-Poll</strong> 控制帧。</li><li><strong>场景</strong>：STA 从睡眠中醒来，主动问 AP：“有没有缓存给我的单播数据？有就赶紧发。”</li></ul></li><li><p><strong><code>static inline bool ieee80211_check_tim(..., u16 aid)</code></strong></p><ul><li><strong>作用</strong>：检查 <strong>TIM (Traffic Indication Map)</strong> 位图。</li><li><strong>场景</strong>：STA 收到 Beacon 帧后，调用此函数查看自己的 AID 对应的位是否被置 1。如果是，说明 AP 有货，该发 PS-Poll 了。</li></ul></li></ul><h4 id="_3-扫描、认证与关联" tabindex="-1">3. 扫描、认证与关联 <a class="header-anchor" href="#_3-扫描、认证与关联" aria-label="Permalink to &quot;3. 扫描、认证与关联&quot;">​</a></h4><p>这是 MLME 的核心流程。</p><ul><li><p><strong><code>int ieee80211_request_scan(...)</code></strong></p><ul><li><strong>作用</strong>：发起 <strong>主动扫描</strong>。</li></ul></li><li><p><strong><code>void ieee80211_send_probe_req(...)</code></strong></p><ul><li><strong>作用</strong>：发送 <strong>Probe Request</strong> 管理帧。</li><li><strong>参数</strong>：<code>ssid</code> 和 <code>ie</code> (Information Elements) 决定了你在问什么。</li></ul></li><li><p><strong><code>void ieee80211_send_auth(...)</code></strong></p><ul><li><strong>作用</strong>：发送 <strong>Authentication</strong> 帧。这是连接的第一步，可以是 Open System 也可以是 Shared Key。</li></ul></li><li><p><strong><code>static void ieee80211_send_assoc(...)</code></strong></p><ul><li><strong>作用</strong>：发送 <strong>Association Request</strong> 帧。</li><li><strong>时机</strong>：认证通过后调用。它会携带所有支持的速率和能力信息。</li></ul></li></ul><h4 id="_4-mesh-路由-802-11s-hwmp" tabindex="-1">4. Mesh 路由（802.11s / HWMP） <a class="header-anchor" href="#_4-mesh-路由-802-11s-hwmp" aria-label="Permalink to &quot;4. Mesh 路由（802.11s / HWMP）&quot;">​</a></h4><p>如果你在写 Mesh 相关的代码，这几个函数是 HWMP 协议在内核中的具体实现入口。</p><ul><li><p><strong><code>struct mesh_path *mesh_path_lookup(..., const u8 *dst)</code></strong></p><ul><li><strong>作用</strong>：在 Mesh 路由表中查找去往 <code>dst</code> 的路径。</li><li><strong>返回</strong>：找不到返回 NULL，找到返回 <code>mesh_path</code> 结构体。这是转发数据的第一步。</li></ul></li><li><p><strong><code>void mesh_path_tx_pending(struct mesh_path *mpath)</code></strong></p><ul><li><strong>作用</strong>：发送 <code>mpath-&gt;frame_queue</code> 里积压的数据包。</li><li><strong>场景</strong>：当路由发现完成（比如收到了 PREP）后，内核会调用此函数把刚才堵在路口的包放行。</li></ul></li><li><p><strong><code>static int mesh_path_sel_frame_tx(enum mpath_frame_type action, ...)</code></strong></p><ul><li><strong>作用</strong>：通用的 HWMP 帧发送函数。</li><li><strong>支持</strong>：既发 <strong>PREQ</strong> (Path Request)，也发 <strong>PREP</strong> (Path Reply)。参数里的 <code>metric</code> 就是那条著名的“airtime”开销。</li></ul></li><li><p><strong><code>static void hwmp_preq_frame_process(...)</code></strong></p><ul><li><strong>作用</strong>：处理收到的 PREQ 帧。这是 Mesh 节点互相协作找路的核心逻辑。</li></ul></li></ul><h4 id="_5-设备注册与底层操作" tabindex="-1">5. 设备注册与底层操作 <a class="header-anchor" href="#_5-设备注册与底层操作" aria-label="Permalink to &quot;5. 设备注册与底层操作&quot;">​</a></h4><p>这是驱动开发者最先接触的 API。</p><ul><li><p><strong><code>struct ieee80211_hw *ieee80211_alloc_hw(...)</code></strong></p><ul><li><strong>作用</strong>：分配一个 <code>ieee80211_hw</code> 设备结构以及驱动的私有数据 <code>priv</code>。一切的开始。</li></ul></li><li><p><strong><code>int ieee80211_register_hw(struct ieee80211_hw *hw)</code></strong></p><ul><li><strong>作用</strong>：向内核注册这个硬件设备。从这一刻起，你的网卡才在系统中“活着”。</li></ul></li><li><p><strong><code>int ieee80211_hw_config(..., u32 changed)</code></strong></p><ul><li><strong>作用</strong>：配置硬件参数。</li><li><strong>参数</strong>：<code>changed</code> 指定了改什么（比如改信道用 <code>IEEE80211_CONF_CHANGE_CHANNEL</code>）。这个函数通常会下沉到驱动的 <code>config()</code> 回调。</li></ul></li><li><p><strong><code>void ieee80211_rx_irqsafe(struct ieee80211_hw *hw, struct sk_buff *skb)</code></strong></p><ul><li><strong>作用</strong>：<strong>接收数据包</strong>。</li><li><strong>特性</strong>：正如其名，它可以在 <strong>硬件中断上下文</strong> 中安全调用。它会利用软中断（tasklet）把收包工作延后处理。</li></ul></li></ul><h4 id="_6-rx-处理与状态" tabindex="-1">6. RX 处理与状态 <a class="header-anchor" href="#_6-rx-处理与状态" aria-label="Permalink to &quot;6. RX 处理与状态&quot;">​</a></h4><p>收包不仅仅是把 SKB 往上层递，还要检查 FCS、解密状态和重排序。</p><ul><li><p><strong><code>struct ieee80211_rx_status *IEEE80211_SKB_RXCB(struct sk_buff *skb)</code></strong></p><ul><li><strong>作用</strong>：从 SKB 的控制块 (<code>cb</code>) 中提取 <code>rx_status</code>。</li><li><strong>重点</strong>：硬件驱动收包后，必须把信号强度、速率、MAC 时间戳等信息填在这个结构体里，放进去 <code>skb-&gt;cb</code>，再交给 <code>mac80211</code>。</li></ul></li><li><p><strong><code>static ieee80211_rx_result ieee80211_rx_h_check(struct ieee80211_rx_data *rx)</code></strong></p><ul><li><strong>作用</strong>：RX 处理的第一道关卡。</li><li><strong>逻辑</strong>：检查是否是重复帧（Retransmission）。如果是，增加 <code>dot11FrameDuplicateCount</code> 计数器，并丢弃。</li></ul></li><li><p><strong><code>static bool ieee80211_sta_manage_reorder_buf(...)</code></strong></p><ul><li><strong>作用</strong>：管理重排序缓冲区的具体实现逻辑。它决定了这个包该进缓冲区等待，还是可以直接交给网络栈。</li></ul></li></ul><hr><h3 id="标志位字典-ieee80211-rx-status" tabindex="-1">标志位字典：<code>ieee80211_rx_status</code> <a class="header-anchor" href="#标志位字典-ieee80211-rx-status" aria-label="Permalink to &quot;标志位字典：`ieee80211_rx_status`&quot;">​</a></h3><p>这是 <code>mac80211</code> 驱动开发中最容易出错的地方之一。<code>rx_status</code> 结构体里的 <code>flag</code> 是一个 32 位位域。硬件驱动负责把这些位填对，<code>mac80211</code> 负责根据这些位做正确的事。</p><p>下面这个表格是我在调试收包问题时经常翻的“天书”。我把含义稍微展开了点，免得你看手册时一脸懵。</p><p><strong>表 12-1：Rx Flags (<code>ieee80211_rx_status</code> 的 flag 字段)</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">Linux 符号常量</th><th style="text-align:left;">位 (Bit)</th><th style="text-align:left;">真实含义与实战提示</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>RX_FLAG_MMIC_ERROR</strong></td><td style="text-align:left;">0</td><td style="text-align:left;"><strong>Michael MIC 错误</strong>。<br>这个帧通过了 CRC 校验，但内容被篡改了。通常发生在 TKIP 加密时。如果是这个错，直接丢包。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_DECRYPTED</strong></td><td style="text-align:left;">1</td><td style="text-align:left;"><strong>硬件已解密</strong>。<br>极其重要的标志。如果硬件帮你解密了（WEP/WPA/WPA2），必须置此位。内核看到它就知道不用再跑软件解密算法了。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_MMIC_STRIPPED</strong></td><td style="text-align:left;">3</td><td style="text-align:left;"><strong>MIC 已被剥离</strong>。<br>硬件不仅解了密，还把尾部的 MIC 校验码给删了。内核会据此计算 MIC。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_IV_STRIPPED</strong></td><td style="text-align:left;">4</td><td style="text-align:left;"><strong>IV/ICV 已被剥离</strong>。<br>硬件解密后把头部的 IV (Initialization Vector) 和尾部的 ICV (Integrity Check Value) 都去掉了。置此位说明你给内核的数据是“干净”的明文 payload。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_FAILED_FCS_CRC</strong></td><td style="text-align:left;">5</td><td style="text-align:left;"><strong>FCS 校验失败</strong>。<br>这包是坏的。虽然你收到了，但 FCS (Frame Check Sequence) 对不上。内核通常会直接静默丢弃。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_FAILED_PLCP_CRC</strong></td><td style="text-align:left;">6</td><td style="text-align:left;"><strong>PLCP 校验失败</strong>。<br>物理层的前导码和信号头就错了。这通常是信号太差导致的。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_MACTIME_START</strong></td><td style="text-align:left;">7</td><td style="text-align:left;"><strong>时间戳有效（起始时刻）</strong>。<br><code>rx_status-&gt;mactime</code> 字段里存的是 <strong>帧第一个符号到达的时间</strong>。对于需要精确测距或同步的场景（如某些定位协议）至关重要。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_SHORTPRE</strong></td><td style="text-align:left;">8</td><td style="text-align:left;"><strong>短前导码</strong>。<br>使用了 802.11b 的 Short Preamble 模式。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_HT</strong></td><td style="text-align:left;">9</td><td style="text-align:left;"><strong>High Throughput (11n)</strong>。<br>这是 802.11n 的帧。注意，此时 <code>rate_idx</code> 字段存的是 MCS 索引，不是传统的 legacy rate。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_40MHZ</strong></td><td style="text-align:left;">10</td><td style="text-align:left;"><strong>HT40 模式</strong>。<br>使用了 40MHz 信道带宽。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_SHORT_GI</strong></td><td style="text-align:left;">11</td><td style="text-align:left;"><strong>短保护间隔</strong>。<br>用了 400ns 的 Short Guard Interval，速度比 800ns 的 GI 快一点。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_NO_SIGNAL_VAL</strong></td><td style="text-align:left;">12</td><td style="text-align:left;"><strong>无信号强度</strong>。<br>硬件没测到信号强度 (RSSI)，或者根本不支持。<code>rx_status-&gt;signal</code> 字段此时无效。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_HT_GF</strong></td><td style="text-align:left;">13</td><td style="text-align:left;"><strong>HT Greenfield</strong>。<br>这是 802.11n 的 Greenfield 模式，没有为了兼容 802.11a/g 而加的 Training Field。速度最快，但老设备听不懂。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_AMPDU_DETAILS</strong></td><td style="text-align:left;">14</td><td style="text-align:left;"><strong>A-MPDU 详情已知</strong>。<br>这个包是聚合帧的一部分。此时 <code>rx_status</code> 里的 <code>ampdu_ref</code> 必须有效，用于区分不同的 A-MPDU 突发。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_AMPDU_REPORT_ZEROLEN</strong></td><td style="text-align:left;">15</td><td style="text-align:left;"><strong>驱动报告零长度子帧</strong>。<br>这是一个比较特殊的硬件行为，有些硬件会把聚合帧里的空包也报告上来。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_AMPDU_IS_ZEROLEN</strong></td><td style="text-align:left;">16</td><td style="text-align:left;"><strong>这是一个零长度子帧</strong>。<br>对应上面的报告，标记这个包本身就是空的，通常用于监控。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_AMPDU_LAST_KNOWN</strong></td><td style="text-align:left;">17</td><td style="text-align:left;"><strong>最后一帧已知</strong>。<br>驱动知道这是这个 A-MPDU 突发的最后一包。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_AMPDU_IS_LAST</strong></td><td style="text-align:left;">18</td><td style="text-align:left;"><strong>这是最后一帧</strong>。<br>这个包就是该 A-MPDU 的终结者。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_AMPDU_DELIM_CRC_ERROR</strong></td><td style="text-align:left;">19</td><td style="text-align:left;"><strong>分隔符 CRC 错误</strong>。<br>在 A-MPDU 中，子帧之间有 Delimiter。如果这个 Delimiter 的 CRC 挂了，说明硬件解析同步出了问题。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_AMPDU_DELIM_CRC_KNOWN</strong></td><td style="text-align:left;">20</td><td style="text-align:left;"><strong>分隔符 CRC 值有效</strong>。<br>如果置位，说明 <code>rx_status-&gt;ampdu_delimiter_crc</code> 字段存着那个算出来的 CRC 值。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_MACTIME_END</strong></td><td style="text-align:left;">21</td><td style="text-align:left;"><strong>时间戳有效（结束时刻）</strong>。<br><code>mactime</code> 记录的是 <strong>帧最后一个符号（含 FCS）收完的时间</strong>。和 START 标志二选一。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_VHT</strong></td><td style="text-align:left;">22</td><td style="text-align:left;"><strong>Very High Throughput (11ac)</strong>。<br>这是 802.11ac 的帧。<code>rate_idx</code> 此时存的是 VHT MCS 索引。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_80MHZ</strong></td><td style="text-align:left;">23</td><td style="text-align:left;"><strong>VHT80 模式</strong>。<br>802.11ac，使用了 80MHz 带宽。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_80P80MHZ</strong></td><td style="text-align:left;">24</td><td style="text-align:left;"><strong>VHT80+80 模式</strong>。<br>使用了两个不连续的 80MHz 通道。这是 802.11ac 的高级特性。</td></tr><tr><td style="text-align:left;"><strong>RX_FLAG_160MHZ</strong></td><td style="text-align:left;">25</td><td style="text-align:left;"><strong>VHT160 模式</strong>。<br>连续的 160MHz 带宽。不仅需要硬件支持，还得看当地法规让不让你用这么宽的频段。</td></tr></tbody></table><hr><h3 id="本章回响" tabindex="-1">本章回响 <a class="header-anchor" href="#本章回响" aria-label="Permalink to &quot;本章回响&quot;">​</a></h3><p>好了，这就是这本书里关于无线网络的最后一块拼图。</p><p>回首这一章，我们实际上是在Linux内核里重建了一座<strong>巴别塔</strong>。我们在物理层（PHY）通过 <code>ieee80211_hw</code> 与硬件对话，在 MAC 层通过 <code>mac80211</code> 实现了 CSMA/CA 的秩序，又通过 FullMAC 与软 MAC 的博弈，看到了驱动开发者的两难选择。</p><p>我们看到了 802.11 协议族是如何一步步从单纯的<strong>避让</strong>（CSMA/CA），进化到<strong>贪婪</strong>（802.11n 的聚合），再到<strong>智能</strong>（802.11s 的 Mesh 路由）。</p><p>还记得本章开头那个问题吗——为什么 Wi-Fi 在Linux里这么复杂？ 现在答案很清楚了：<strong>因为它试图在一个充满噪声、不可靠的共享介质上，模拟出一条可靠、高速的点对点专线。</strong></p><ul><li><strong>FullMAC</strong> 把复杂性塞进了黑盒，硬件厂商为你挡了一枪，但也锁住了你的手脚。</li><li><strong>SoftMAC (mac80211)</strong> 把复杂性交给了内核，你得自己处理 TIM、Buffer、重排序，但你拥有了空气中的绝对控制权。</li></ul><p>当你下次看着 <code>iw</code> 输出的连击信息，或者在内核日志里翻到 <code>ieee80211_rx: mmic_error</code> 时，希望你能意识到：这不仅仅是一条日志，这是这颗芯片为了把那一比特数据从天线送进内存，与混乱的无线电波搏斗后的战损报告。</p><p>这章结束了。收起你的天线，我们下一章见。那里我们将从“看不见的波”切换到“看得见却摸不着的光纤”——<strong>RDMA</strong>。在那里，内核甚至不再插手数据传输，只是为了把那条路铺平。</p><hr><h2 id="练习题" tabindex="-1">练习题 <a class="header-anchor" href="#练习题" aria-label="Permalink to &quot;练习题&quot;">​</a></h2><h3 id="练习-1-understanding" tabindex="-1">练习 1：understanding <a class="header-anchor" href="#练习-1-understanding" aria-label="Permalink to &quot;练习 1：understanding&quot;">​</a></h3><p><strong>题目</strong>：在 Infrastructure BSS（基础架构模式）下，当一个无线客户端（STA）向接入点（AP）发送数据帧，且该数据最终需转发至外部有线网络时，802.11 MAC 头部帧控制字段中的 ToDS 和 FromDS 位应分别被设置为什么值？</p><details><summary>答案与解析</summary><p><strong>答案</strong>：ToDS = 1, FromDS = 0</p><p><strong>解析</strong>：根据 802.11 规范，ToDS（Distribution System）位表示数据帧发往分发系统（即 AP），FromDS 位表示数据帧来自分发系统。当客户端向 AP 发送数据（由 AP 转发出去）时，数据是进入分发系统的，因此 ToDS 置 1，FromDS 置 0。反之，当 AP 向客户端发送数据时，FromDS 为 1，ToDS 为 0。</p></details><h3 id="练习-2-understanding" tabindex="-1">练习 2：understanding <a class="header-anchor" href="#练习-2-understanding" aria-label="Permalink to &quot;练习 2：understanding&quot;">​</a></h3><p><strong>题目</strong>：当 mac80211 子系统中的接入点（AP）接收到一个客户端发送的 Null Data Packet（空数据包），且发现帧控制中的 Power Management 位为 1 时，AP 接下来会执行什么操作？</p><details><summary>答案与解析</summary><p><strong>答案</strong>：AP 会将该客户端标记为进入休眠状态，并开始将发往该客户端的单播数据包缓存到 ps_tx_buf 缓冲区中。</p><p><strong>解析</strong>：Null Data Packet 不包含有效载荷，主要用于电源管理通知。根据 Power Save Mode 机制，当 PM 位为 1 时，表示站点即将进入省电模式。AP 收到此通知后，会将后续发往该站点的单播包存入该站点对应的 ps_tx_buf 队列（最多 128 个），直到站点通过 PS-Poll 或 Null Data 包唤醒并取回数据。</p></details><h3 id="练习-3-application" tabindex="-1">练习 3：application <a class="header-anchor" href="#练习-3-application" aria-label="Permalink to &quot;练习 3：application&quot;">​</a></h3><p><strong>题目</strong>：假设你正在开发一个 FullMAC 类型的无线网卡驱动，与 SoftMAC（使用 mac80211）驱动相比，在内核空间处理 802.11 管理帧（如 Association Request、Authentication）的逻辑责任有何主要不同？</p><details><summary>答案与解析</summary><p><strong>答案</strong>：在 FullMAC 驱动架构中，MLME（MAC 层管理实体）逻辑主要由固件或硬件处理，内核驱动通常只负责数据面的传输和基本控制；而在 SoftMAC（mac80211）架构中，MLME 逻辑（如关联、认证、扫描状态的机）由内核中的 mac80211 子系统和用户空间守护进程（如 wpa_supplicant/hostapd）共同处理。</p><p><strong>解析</strong>：FullMAC 设备自身处理大部分 MAC 层管理功能（如状态的维护、帧的交互），内核驱动相对轻量。mac80211 是一个 SoftMAC 框架，它将复杂的协议状态机放在内核软件中实现，从而统一不同硬件的行为，并允许更灵活的软件定义功能（如 Mesh 网络的复杂路由）。</p></details><h3 id="练习-4-thinking" tabindex="-1">练习 4：thinking <a class="header-anchor" href="#练习-4-thinking" aria-label="Permalink to &quot;练习 4：thinking&quot;">​</a></h3><p><strong>题目</strong>：IEEE 802.11n 引入了 A-MPDU（Aggregated MAC Protocol Data Unit）和 A-MSDU（Aggregated MAC Service Data Unit）两种聚合技术来提高吞吐量。请从“发生重传时的开销”角度分析，为什么 A-MPDU 通常比 A-MSDU 更适合高误码率的无线环境？</p><details><summary>答案与解析</summary><p><strong>答案</strong>：因为 A-MPDU 的重传粒度是 MPDU（MAC 层协议数据单元），而 A-MSDU 的重传粒度是整个聚合后的 MSDU。在 A-MPDU 中，如果聚合块中只有一个子帧出错或丢失，接收端可以通过 Block Ack 机制仅请求重传出错的那一个子帧，而无需重传整个聚合块。相反，A-MSDU 将多个 MSDU 打包成一个大帧，如果传输过程中发生误码导致 CRC 校验失败，整个大帧都需要重传，这在信道质量差（高误码率）时会显著降低有效吞吐量。</p><p><strong>解析</strong>：这道题考察对底层链路效率的深度思考。虽然 A-MSDU 减少了头部的开销，但其重传机制是“全有或全无”的。A-MPDU 配合 Block Ack 机制提供了更细粒度的错误恢复能力（Selective Retransmission），在不可靠的无线信道中，这种特性带来的效率收益通常超过了其稍高的头部开销。</p></details><hr><h2 id="要点提炼" tabindex="-1">要点提炼 <a class="header-anchor" href="#要点提炼" aria-label="Permalink to &quot;要点提炼&quot;">​</a></h2><p>Linux 内核将无线网络视为独立子系统 <code>mac80211</code>，而非以太网的简单变体，主要归因于无线物理介质的高不可靠性（频繁丢包）和独特的介质访问方式（从冲突检测 CD 转向冲突避免 CA）。为了应对 802.11 协议的快速迭代，Linux 主流采用 <strong>SoftMAC</strong> 架构：复杂的 MAC 层逻辑（如组帧、加密、重传）由内核统一接管，驱动仅负责硬件交互，从而获得了极高的灵活性和控制力。</p><p>802.11 的 MAC 头部比以太网复杂得多，最多包含 4 个地址字段（MAC Header 4 Addresses）和丰富的帧控制位，这些结构定义了帧的具体身份（管理/控制/数据）、流向（ToDS/FromDS）及行为属性（如省电模式、重传标志）。这种复杂性源于无线网络中的流量转发（AP 转发数据）和特殊机制需求，驱动开发必须深入理解这些字段才能正确解析和构造数据帧。</p><p>在 <strong>Infrastructure</strong> 基础架构模式下，客户端必须通过认证和关联两个步骤才能接入网络，并获取唯一的 AID（关联 ID）。为了解决移动设备（如手机、笔记本）的续航问题，协议设计了精细的 <strong>Power Save Mode（节电模式）</strong>：客户端通过发送 Null Data 帺金标志位通知 AP 休眠，AP 维护每个站点的 <code>ps_tx_buf</code> 缓存单播包，并利用 Beacon 帧中的 TIM（流量指示图）位图来通知客户端“有货待取”，客户端再通过 PS-Poll 帧主动“提货”。</p><p><strong>MLME（MAC 层管理实体）</strong> 负责处理网络发现与维护的底层逻辑。为了寻找 AP，设备会进行 <strong>Scanning（扫描）</strong>：在 5GHz 雷达频段必须使用被动扫描（静默监听 Beacon），而在普通频段通常使用主动扫描（发送 Probe Request 并等待 Probe Response）。当客户端在移动中发现信号更好的 AP 时，会触发 <strong>Roaming（漫游）</strong> 机制，通过发送带有原 AP 地址的 Reassociation Request 帧与新 AP 建立连接，实现网络的无缝切换。</p><p>在内核实现层面，<code>mac80211</code> 框架将通用逻辑与硬件细节解耦。核心结构体 <code>ieee80211_hw</code> 作为硬件的抽象身份证，而 <code>ieee80211_ops</code> 回调函数集则定义了驱动的操作规范（如 <code>tx</code> 发包、<code>config</code> 配置信道、<code>start</code> 启动设备）。每个连接的对端站点在内核中对应一个 <code>sta_info</code> 结构体，它不仅存储 MAC 地址和统计信息，还管理着诸如节电缓冲队列（<code>ps_tx_buf</code>）等关键状态，是驱动维护连接关系的核心数据结构。</p>',62)])])}const p=e(n,[["render",l]]);export{u as __pageData,p as default};
